import React, { useState } from 'react';
import axios from 'axios';
import './App.css';

const API_BASE = 'http://localhost:5001/api';

function App() {
  const [activeTab, setActiveTab] = useState('checklist');

  return (
    <div className="app-container">
      <div className="header">
        <h1>📄 IPQC OCR System</h1>
        <p>Extract data from IPQC checklists and fill Excel automatically</p>
      </div>

      <div className="tab-bar">
        <button
          className={`tab-btn ${activeTab === 'checklist' ? 'active' : ''}`}
          onClick={() => setActiveTab('checklist')}
        >
          📋 IPQC Checklist
        </button>
        <button
          className={`tab-btn ${activeTab === 'ocr' ? 'active' : ''}`}
          onClick={() => setActiveTab('ocr')}
        >
          🔗 Manual OCR
        </button>
      </div>

      {activeTab === 'checklist' ? <ChecklistTab /> : <OcrTab />}

      <div className="footer">
        <p>IPQC OCR System v2.0 | Powered by Azure Document Intelligence</p>
      </div>
    </div>
  );
}

// ========== IPQC CHECKLIST TAB ==========
function ChecklistTab() {
  const [date, setDate] = useState(new Date().toISOString().split('T')[0]);
  const [shift, setShift] = useState('');
  const [line, setLine] = useState('');
  const [loading, setLoading] = useState(false);
  const [checklists, setChecklists] = useState([]);
  const [error, setError] = useState('');
  const [processing, setProcessing] = useState(null);
  const [processResult, setProcessResult] = useState(null);

  const handleFetch = async () => {
    setLoading(true);
    setError('');
    setChecklists([]);
    setProcessResult(null);

    try {
      const payload = {};
      if (date) payload.date = date;
      if (shift) payload.shift = shift;
      if (line) payload.line = line;

      const response = await axios.post(`${API_BASE}/ipqc-checklist/fetch`, payload);

      if (response.data.success) {
        setChecklists(response.data.data || []);
        if ((response.data.data || []).length === 0) {
          setError('No checklists found for the selected filters.');
        }
      } else {
        setError(response.data.error || 'Failed to fetch checklists');
      }
    } catch (err) {
      setError(err.response?.data?.error || err.message || 'Failed to fetch checklists');
    } finally {
      setLoading(false);
    }
  };

  const handleProcess = async (checklist, index) => {
    setProcessing(index);
    setProcessResult(null);
    setError('');

    try {
      const response = await axios.post(`${API_BASE}/ipqc-checklist/process-item`, {
        checklist
      });

      if (response.data.success) {
        setProcessResult({ index, ...response.data });
      } else {
        setError(response.data.error || 'Processing failed');
      }
    } catch (err) {
      setError(err.response?.data?.error || err.message || 'OCR processing failed');
    } finally {
      setProcessing(null);
    }
  };

  const handleDownload = (filename) => {
    window.open(`${API_BASE}/ipqc-ocr/download/${filename}`, '_blank');
  };

  return (
    <div className="main-card">
      <h2 className="section-title">📋 IPQC Checklist - Fetch & Process</h2>
      <p className="section-desc">Fetch IPQC checklists by date, shift, and line. Then process pages through OCR.</p>

      <div className="filter-row">
        <div className="filter-item">
          <label>Date</label>
          <input type="date" value={date} onChange={(e) => setDate(e.target.value)} disabled={loading} />
        </div>
        <div className="filter-item">
          <label>Shift</label>
          <select value={shift} onChange={(e) => setShift(e.target.value)} disabled={loading}>
            <option value="">All Shifts</option>
            <option value="Day">Day</option>
            <option value="Night">Night</option>
          </select>
        </div>
        <div className="filter-item">
          <label>Line</label>
          <select value={line} onChange={(e) => setLine(e.target.value)} disabled={loading}>
            <option value="">All Lines</option>
            <option value="Line A">Line A</option>
            <option value="Line B">Line B</option>
            <option value="Line C">Line C</option>
            <option value="Line D">Line D</option>
          </select>
        </div>
        <div className="filter-item filter-btn-wrap">
          <button onClick={handleFetch} disabled={loading} className="fetch-btn">
            {loading ? <><span className="spinner"></span> Fetching...</> : <>🔍 Fetch Checklists</>}
          </button>
        </div>
      </div>

      {error && <div className="error-message">❌ {error}</div>}

      {checklists.length > 0 && (
        <div className="checklist-results">
          <h3>Found {checklists.length} Checklist(s)</h3>
          <div className="checklist-table-wrapper">
            <table className="checklist-table">
              <thead>
                <tr>
                  <th>#</th>
                  <th>Date</th>
                  <th>Line</th>
                  <th>Shift</th>
                  <th>Pages</th>
                  <th>Action</th>
                </tr>
              </thead>
              <tbody>
                {checklists.map((item, idx) => (
                  <tr key={idx} className={processResult?.index === idx ? 'row-processed' : ''}>
                    <td>{idx + 1}</td>
                    <td>{item.date || '—'}</td>
                    <td>{item.Line || '—'}</td>
                    <td>{item.Shift || '—'}</td>
                    <td><span className="page-badge">{item.totalPages || 0} pages</span></td>
                    <td>
                      {processing === idx ? (
                        <span className="processing-label"><span className="spinner small"></span> Processing...</span>
                      ) : processResult?.index === idx ? (
                        <div className="action-btns">
                          <span className="done-label">✅ Done</span>
                          {processResult.excelGenerated && (
                            <button className="download-btn small" onClick={() => handleDownload(processResult.outputFile)}>
                              📥 Excel
                            </button>
                          )}
                        </div>
                      ) : (
                        <button className="process-btn small" onClick={() => handleProcess(item, idx)} disabled={processing !== null || item.totalPages === 0}>
                          🚀 Process OCR
                        </button>
                      )}
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      )}

      {processResult && (
        <div className="process-result">
          <h3>✅ OCR Processing Complete</h3>
          <div className="result-summary">
            <div className="result-item"><span className="label">Date:</span><span className="value">{checklists[processResult.index]?.date}</span></div>
            <div className="result-item"><span className="label">Line:</span><span className="value">{checklists[processResult.index]?.Line}</span></div>
            <div className="result-item"><span className="label">Shift:</span><span className="value">{checklists[processResult.index]?.Shift}</span></div>
            <div className="result-item"><span className="label">Pages Processed:</span><span className="value">{processResult.pagesProcessed}</span></div>
            <div className="result-item"><span className="label">Excel Generated:</span><span className="value">{processResult.excelGenerated ? 'Yes ✅' : 'No ❌'}</span></div>
          </div>

          {processResult.extractedData && processResult.extractedData.length > 0 && (
            <div className="extracted-pages">
              <h4>Extracted Data by Page</h4>
              {processResult.extractedData.map((page, idx) => (
                <div key={idx} className="page-data">
                  <h5>Page {page.pageNumber || idx + 1}</h5>
                  {page.error ? (
                    <p className="page-error">Error: {page.error}</p>
                  ) : (
                    <div className="page-details">
                      {page.serialNumbers?.length > 0 && (
                        <div className="detail-row">
                          <span className="detail-label">Serial Numbers ({page.serialNumbers.length}):</span>
                          <div className="serial-grid">
                            {page.serialNumbers.slice(0, 10).map((s, si) => (
                              <span key={si} className="serial-item">{s}</span>
                            ))}
                            {page.serialNumbers.length > 10 && (
                              <span className="serial-item more">+{page.serialNumbers.length - 10} more</span>
                            )}
                          </div>
                        </div>
                      )}
                      {page.temperatures?.length > 0 && (
                        <div className="detail-row">
                          <span className="detail-label">Temperatures:</span>
                          <span>{page.temperatures.join(', ')}</span>
                        </div>
                      )}
                      {page.dates?.length > 0 && (
                        <div className="detail-row">
                          <span className="detail-label">Dates:</span>
                          <span>{page.dates.join(', ')}</span>
                        </div>
                      )}
                    </div>
                  )}
                </div>
              ))}
            </div>
          )}

          {processResult.excelGenerated && (
            <button className="download-btn large" onClick={() => handleDownload(processResult.outputFile)}>
              📥 Download Filled Excel
            </button>
          )}
        </div>
      )}
    </div>
  );
}

// ========== MANUAL OCR TAB ==========
function OcrTab() {
  const [pdfUrls, setPdfUrls] = useState('');
  const [loading, setLoading] = useState(false);
  const [status, setStatus] = useState('');
  const [error, setError] = useState('');
  const [result, setResult] = useState(null);
  const [extractedData, setExtractedData] = useState(null);

  const handleProcessOCR = async () => {
    if (!pdfUrls.trim()) { setError('Please enter PDF URLs (one per line)'); return; }
    setLoading(true);
    setStatus('Processing PDF files with Azure Document Intelligence...');
    setError('');
    setResult(null);
    setExtractedData(null);

    try {
      const urls = pdfUrls.split('\n').map(url => url.trim()).filter(url => url);
      setStatus(`Processing ${urls.length} PDF file(s)...`);
      const response = await axios.post(`${API_BASE}/ipqc-ocr/process-from-urls`, { pdfUrls: urls });
      if (response.data.success) {
        setResult(response.data);
        setExtractedData(response.data.extractedData);
        setStatus('✅ OCR Complete! Excel file ready for download.');
      } else {
        setError(response.data.error || 'OCR processing failed');
        setStatus('');
      }
    } catch (err) {
      setError(err.response?.data?.error || err.message || 'Failed to process OCR');
      setStatus('');
    } finally {
      setLoading(false);
    }
  };

  const handleDownloadExcel = () => {
    if (result && result.outputFile) {
      const filename = result.outputFile.includes('\\') || result.outputFile.includes('/')
        ? result.outputFile.split(/[\\\/]/).pop() : result.outputFile;
      window.open(`${API_BASE}/ipqc-ocr/download/${filename}`, '_blank');
    }
  };

  return (
    <div className="main-card">
      <h2 className="section-title">🔗 Manual OCR Processing</h2>
      <p className="section-desc">Paste PDF URLs to process through Azure OCR and generate Excel.</p>

      <div className="input-section">
        <label htmlFor="pdfUrls"><span className="label-icon">🔗</span> Enter PDF URLs (one per line):</label>
        <textarea
          id="pdfUrls"
          value={pdfUrls}
          onChange={(e) => setPdfUrls(e.target.value)}
          placeholder={`https://example.com/page1.pdf\nhttps://example.com/page2.pdf`}
          rows={6}
          disabled={loading}
        />
      </div>

      <div className="button-section">
        <button onClick={handleProcessOCR} disabled={loading || !pdfUrls.trim()} className="process-btn">
          {loading ? <><span className="spinner"></span> Processing...</> : <>🚀 Process OCR</>}
        </button>
        {result && (
          <button onClick={handleDownloadExcel} className="download-btn">📥 Download Excel</button>
        )}
      </div>

      {status && <div className="status-message">{status}</div>}
      {error && <div className="error-message">❌ {error}</div>}

      {extractedData && (
        <div className="extracted-data">
          <h3>📋 Extracted Data Preview</h3>
          <div className="data-grid">
            {extractedData.date && <div className="data-item"><span className="label">Date:</span><span className="value">{extractedData.date}</span></div>}
            {extractedData.lotNumber && <div className="data-item"><span className="label">Lot Number:</span><span className="value">{extractedData.lotNumber}</span></div>}
            {extractedData.type && <div className="data-item"><span className="label">Type:</span><span className="value">{extractedData.type}</span></div>}
            {extractedData.cell && <div className="data-item"><span className="label">Cell:</span><span className="value">{extractedData.cell}</span></div>}
          </div>
          {extractedData.serialNumbers && extractedData.serialNumbers.length > 0 && (
            <div className="serial-section">
              <h4>Serial Numbers ({extractedData.serialNumbers.length})</h4>
              <div className="serial-grid">
                {extractedData.serialNumbers.slice(0, 20).map((serial, idx) => (
                  <span key={idx} className="serial-item">{serial}</span>
                ))}
                {extractedData.serialNumbers.length > 20 && (
                  <span className="serial-item more">+{extractedData.serialNumbers.length - 20} more</span>
                )}
              </div>
            </div>
          )}
        </div>
      )}
    </div>
  );
}

export default App;
